  var results1 = Array.isArray(search1?.results) ? search1.results : [];
  var results2 = Array.isArray(search2?.results) ? search2.results : [];
  var seen = new Set();
  var allCandidates = [];
  for (var r of [...results1, ...results2]) {
    if (r.conditionId && !seen.has(r.conditionId)) {
      seen.add(r.conditionId);
      allCandidates.push(r);
    }
  }

  // Phase 2: Deterministic semantic targeting — rank noisy candidate list
  var iranRanked = pickTopSemanticCandidates({
    target: "US or allied boots on the ground, ground invasion, or combat troop deployment in Iran",
    candidates: allCandidates,
    requiredTerms: ["iran", "ground", "troop", "boots", "invasion", "military", "strike", "attack", "combat"],
    avoidTerms: ["sanction", "nuclear", "deal", "diplomat", "negotiat", "protest", "election"],
    limit: 5
