      if (!iranRanked[i].slug) continue;
      var detail = await callMcpSkill({
        toolId: POLY, toolName: "get_event_by_slug",
        args: { slug: iranRanked[i].slug }
      });
      if (detail?.event) iranDetails.push(detail);
    }
  } else {
    // No Iran-specific markets matched — still grab regime context
    regimeData = await callMcpSkill({
      toolId: CRYPTO, toolName: "get_breadth", args: {}
    });
  }

