    target: "instruments reflecting broader risk-off positioning triggered by geopolitical escalation such as an Iran conflict",
    candidates: riskOffCandidates,
    requiredTerms: ["oil", "s&p", "recession", "drawdown", "crash", "bear", "safe", "geopolitical", "escalation", "war"],
    avoidTerms: ["iran", "troop", "ground", "invasion", "boots"],
